pages.css:
.page {
  width: 1242px;
  height: 1660px;
  background-color: #F8F9FA;
  padding: 100px 96px;
  box-sizing: border-box;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
  display: flex;
  flex-direction: column;
}
.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 40px;
}
.header-icon {
  font-size: 40px;
}
.header-label {
  font-size: 36px;
  font-weight: 600;
  color: #666666;
  letter-spacing: 0;
}
.page-title {
  margin-bottom: 56px;
  display: flex;
  flex-direction: column;
  gap: 8px;
}
.title-line {
  font-size: 110px;
  font-weight: 900;
  color: #111111;
  line-height: 1.15;
  letter-spacing: 0;
}
.proof-list {
  display: flex;
  flex-direction: column;
  gap: 28px;
  flex: 1;
}
.proof-item {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 36px 40px;
  border-left: 8px solid #FF4D00;
  box-shadow: 0 8px 24px rgba(0, 0, 0, 0.03);
  display: flex;
  flex-direction: column;
  gap: 12px;
}
.proof-tag {
  font-size: 42px;
  font-weight: 800;
  color: #FF4D00;
}
.proof-text {
  font-size: 38px;
  line-height: 1.5;
  color: #333333;
  font-weight: 400;
}

.page { width: 1242px; height: 1660px; background-color: #F8F8F7; padding: 100px 96px; box-sizing: border-box; display: flex; flex-direction: column; font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif; position: relative; }
.page-header { display: flex; align-items: center; gap: 16px; margin-bottom: 48px; }
.header-icon { font-size: 42px; }
.header-label { font-size: 40px; font-weight: 600; color: #666666; letter-spacing: 0; }
.title-container { margin-bottom: 48px; }
.title-line { font-size: 112px; font-weight: 900; color: #1A1A1A; line-height: 1.15; margin: 0; letter-spacing: 0; }
.highlight-box { background-color: #FFFFFF; border-radius: 16px; padding: 40px 48px; margin-bottom: 48px; border-left: 12px solid #D94A38; box-shadow: 0 8px 24px rgba(0,0,0,0.03); }
.highlight-value { font-size: 92px; font-weight: 800; color: #D94A38; line-height: 1.1; margin-bottom: 12px; letter-spacing: 0; }
.highlight-sub { font-size: 38px; font-weight: 600; color: #666666; line-height: 1.4; letter-spacing: 0; }
.sub-items-list { display: flex; flex-direction: column; gap: 36px; flex-grow: 1; }
.sub-item { display: flex; flex-direction: column; gap: 12px; }
.item-tag { font-size: 40px; font-weight: 800; color: #1A1A1A; display: flex; align-items: center; letter-spacing: 0; }
.item-tag::before { content: ""; display: inline-block; width: 12px; height: 12px; background-color: #D94A38; border-radius: 2px; margin-right: 16px; }
.item-text { font-size: 38px; line-height: 1.55; color: #444444; margin: 0; letter-spacing: 0; }
.footnote { margin-top: auto; padding-top: 32px; border-top: 2px solid #EAEAEA; }
.footnote p { font-size: 34px; color: #999999; margin: 0; line-height: 1.4; letter-spacing: 0; }

.page-04 {
  width: 1242px;
  height: 1660px;
  box-sizing: border-box;
  background-color: #f7f9f8;
  padding: 90px 100px;
  position: relative;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  color: #111;
  letter-spacing: 0;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  font-size: 38px;
  font-weight: 600;
  color: #666;
}

.title-section {
  margin-top: 60px;
  margin-bottom: 60px;
}

.title-line {
  font-size: 104px;
  font-weight: 900;
  line-height: 1.25;
  color: #111;
}

.highlight-section {
  background-color: #1a3a30;
  color: #fff;
  padding: 50px 60px;
  border-radius: 16px;
  margin-bottom: 60px;
  display: flex;
  flex-direction: column;
  justify-content: center;
}

.highlight-value {
  font-size: 100px;
  font-weight: 800;
  line-height: 1.1;
  margin-bottom: 16px;
}

.highlight-sub {
  font-size: 38px;
  font-weight: 400;
  opacity: 0.85;
}

.sub-items-section {
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 12px;
  padding-left: 24px;
  border-left: 6px solid #1a3a30;
}

.sub-tag {
  font-size: 42px;
  font-weight: 700;
  color: #1a3a30;
}

.sub-text {
  font-size: 38px;
  font-weight: 400;
  color: #333;
  line-height: 1.55;
}

.footnote-section {
  position: absolute;
  bottom: 90px;
  right: 100px;
  font-size: 32px;
  color: #999;
  font-weight: 400;
}

.page-05 {
  width: 1242px;
  height: 1660px;
  background-color: #F4F5F7;
  box-sizing: border-box;
  padding: 88px 100px;
  display: flex;
  flex-direction: column;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
}

.page-header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 48px;
}

.header-icon {
  font-size: 40px;
}

.header-label {
  font-size: 36px;
  font-weight: 600;
  color: #6C757D;
  letter-spacing: 0;
}

.page-title {
  margin-bottom: 60px;
}

.title-line {
  font-size: 112px;
  line-height: 1.25;
  font-weight: 800;
  color: #111111;
  letter-spacing: 0;
}

.proof-list {
  display: flex;
  flex-direction: column;
  gap: 40px;
}

.proof-card {
  background-color: #FFFFFF;
  border-radius: 16px;
  padding: 40px 48px;
  box-shadow: 0 6px 20px rgba(0, 0, 0, 0.04);
  display: flex;
  flex-direction: column;
  gap: 20px;
  border: 1px solid rgba(0, 0, 0, 0.03);
}

.proof-tag {
  font-size: 32px;
  font-weight: 700;
  color: #C5221F;
  background-color: #FCE8E6;
  padding: 8px 16px;
  border-radius: 6px;
  align-self: flex-start;
  letter-spacing: 0;
}

.proof-tag::before {
  content: "";
  display: inline-block;
  width: 6px;
  height: 6px;
  background-color: #C5221F;
  border-radius: 50%;
  margin-right: 10px;
  vertical-align: middle;
  position: relative;
  top: -2px;
}

.proof-text {
  font-size: 38px;
  line-height: 1.55;
  color: #3C4043;
  margin: 0;
  font-weight: 400;
  letter-spacing: 0;
}

.page-06 {
  width: 1242px;
  height: 1660px;
  background-color: #F4F5F7;
  padding: 90px 100px;
  box-sizing: border-box;
  font-family: system-ui, -apple-system, BlinkMacSystemFont, "PingFang SC", "Microsoft YaHei", sans-serif;
  letter-spacing: 0;
  display: flex;
  flex-direction: column;
}

.header {
  display: flex;
  align-items: center;
  gap: 16px;
  margin-bottom: 60px;
}

.icon {
  font-size: 40px;
}

.label {
  font-size: 36px;
  font-weight: 600;
  color: #666;
}

.title-section {
  margin-bottom: 70px;
}

.title-line {
  font-size: 112px;
  font-weight: 900;
  line-height: 1.2;
  color: #111;
  margin: 0;
}

.title-line.highlight {
  color: #E63946;
}

.content-section {
  display: flex;
  flex-direction: column;
  gap: 36px;
}

.sub-item {
  display: flex;
  flex-direction: column;
  gap: 16px;
  background: #FFFFFF;
  padding: 36px 44px;
  border-radius: 16px;
  border-left: 12px solid #111;
  box-shadow: 0 10px 30px rgba(0,0,0,0.03);
}

.sub-item:nth-child(2) {
  border-left-color: #E63946;
}

.sub-item:nth-child(3) {
  border-left-color: #457B9D;
}

.tag {
  font-size: 34px;
  font-weight: 800;
  color: #111;
}

.text {
  font-size: 38px;
  line-height: 1.55;
  color: #333;
  margin: 0;
}
